{
  "name": "Alex Aidun - AI Product Portfolio",
  "description": "A showcase of AI products and tools built by Alex Aidun, featuring an interactive AI agent."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Project {
  id: string;
  title: string;
  description: string;
  category: ProjectCategory;
  tags: string[];
  link?: string;
  badge?: string;
}

export enum ProjectCategory {
  ALL = 'All',
  SERVICES = 'Services',
  TOOLS = 'Tools',
  GAMES = 'Games',
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isThinking?: boolean;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { PORTFOLIO_ITEMS, PROFILE } from '../constants';

const SYSTEM_INSTRUCTION = `
You are an AI Assistant representing ${PROFILE.name}.
Your goal is to answer questions about Alex's background, philosophy, and his portfolio projects.

Here is Alex's Bio:
"${PROFILE.bio} ${PROFILE.bio2}"

Here are his projects:
${JSON.stringify(PORTFOLIO_ITEMS)}

Tone: Professional, insightful, concise, and helpful.
If asked about contact info, provide: ${PROFILE.email}.
Do not hallucinate projects not listed here.
Keep responses relatively short (under 100 words) unless asked for deep detail.
`;

export const sendMessageToGemini = async (
  history: { role: 'user' | 'model'; text: string }[],
  newMessage: string
): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // We construct a chat history for context, but for this simple implementation
    // using generateContent with system instructions is often cleaner for single-turn logic,
    // however, to maintain conversation, we will use the chat feature.

    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
      history: history.map(msg => ({
        role: msg.role,
        parts: [{ text: msg.text }]
      }))
    });

    const response: GenerateContentResponse = await chat.sendMessage({ message: newMessage });
    return response.text || "I'm sorry, I couldn't generate a response at the moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I am currently experiencing high traffic. Please try again later.";
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ai';
  icon?: React.ReactNode;
  fullWidth?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  icon, 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-3 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 hover:bg-indigo-500 text-white focus:ring-indigo-500",
    secondary: "bg-slate-800 hover:bg-slate-700 text-slate-200 focus:ring-slate-500 border border-slate-700",
    outline: "bg-transparent border border-slate-600 hover:border-slate-400 text-slate-300 hover:text-white",
    ai: "bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white shadow-lg shadow-indigo-500/20 border border-indigo-500/50"
  };

  const widthClass = fullWidth ? "w-full" : "";

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${widthClass} ${className}`}
      {...props}
    >
      {icon && <span className="mr-2">{icon}</span>}
      {children}
    </button>
  );
};

export default Button;

