  );
};

export default Sidebar;

import React, { useState, useMemo } from 'react';
import { ProjectCategory } from '../types';
import { PORTFOLIO_ITEMS } from '../constants';
import ProjectCard from './ProjectCard';

const Portfolio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<ProjectCategory>(ProjectCategory.ALL);

  const filteredProjects = useMemo(() => {
    if (activeTab === ProjectCategory.ALL) return PORTFOLIO_ITEMS;
    return PORTFOLIO_ITEMS.filter(project => project.category === activeTab);
  }, [activeTab]);

  return (
    <div className="h-full flex flex-col">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4 sticky top-0 bg-slate-950/80 backdrop-blur-md z-10 py-4 -mx-4 px-4 md:mx-0 md:px-0">
        <h2 className="text-3xl font-bold text-white relative inline-block">
          Portfolio
          <span className="absolute -bottom-2 left-0 w-1/3 h-1 bg-indigo-500 rounded-full"></span>
        </h2>

        <div className="flex p-1 bg-slate-900 rounded-lg overflow-x-auto no-scrollbar border border-slate-800">
          {Object.values(ProjectCategory).map((category) => (
            <button
              key={category}
              onClick={() => setActiveTab(category)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-all duration-200 whitespace-nowrap ${
                activeTab === category
                  ? 'bg-slate-800 text-white shadow-sm'
                  : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800/50'
              }`}
            >
              {category}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-6 animate-in slide-in-from-bottom-4 duration-500">
        {filteredProjects.map((project) => (
          <ProjectCard key={project.id} project={project} />
        ))}
      </div>

      {filteredProjects.length === 0 && (
          <div className="text-center py-20">
              <p className="text-slate-500">No projects found in this category.</p>
          </div>
      )}
    </div>
  );
};

export default Portfolio;

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import Portfolio from './components/Portfolio';
import ChatModal from './components/ChatModal';

const App: React.FC = () => {
  const [isChatOpen, setIsChatOpen] = useState(false);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-indigo-500/30 selection:text-indigo-200">

      {/* Mobile Header / Background pattern */}
      <div className="fixed inset-0 z-0 opacity-20 pointer-events-none" 
           style={{
             backgroundImage: 'radial-gradient(circle at 20% 20%, rgba(79, 70, 229, 0.15) 0%, transparent 40%), radial-gradient(circle at 80% 80%, rgba(124, 58, 237, 0.15) 0%, transparent 40%)'
           }}>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-12 md:py-20 relative z-10">
        <div className="flex flex-col lg:flex-row gap-12 lg:gap-24">

          {/* Left Column - Fixed on Desktop */}
          <header className="lg:w-1/3 lg:sticky lg:top-20 lg:h-[calc(100vh-10rem)]">
            <Sidebar onOpenAiChat={() => setIsChatOpen(true)} />
          </header>

          {/* Right Column - Scrollable Content */}
          <main className="lg:w-2/3">
            <Portfolio />
          </main>

        </div>
      </div>

      <ChatModal isOpen={isChatOpen} onClose={() => setIsChatOpen(false)} />
    </div>
  );
};

export default App;

