  const [searchQuery, setSearchQuery] = useState('');

  const filteredItems = useMemo(() => {
    return PORTFOLIO_ITEMS.filter(item => {
      const matchesCategory = activeTab === ProjectCategory.ALL || item.category === activeTab;
      const matchesSearch = 
        item.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.outcome.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()));

      return matchesCategory && matchesSearch;
    });
  }, [activeTab, searchQuery]);

  const featuredProjects = useMemo(() => {
    return PORTFOLIO_ITEMS.filter(item => item.featured);
  }, []);

  const standardProjects = useMemo(() => {
    // If searching or filtering, show all matches in the grid
    if (searchQuery || activeTab !== ProjectCategory.ALL) return filteredItems;
    // Otherwise, show non-featured in the grid
