import React, { useState, useEffect, useRef } from 'react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';
import Button from './Button';

interface ChatModalProps {
  isOpen: boolean;
  onClose: () => void;
  initialInput?: string;
}

const ChatModal: React.FC<ChatModalProps> = ({ isOpen, onClose, initialInput = '' }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'model', text: "Hi! I'm Alex's AI Assistant. Ask me anything about his projects, experience, or what he's building next." }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && initialInput) {
      handleSendInternal(initialInput);
    }
  }, [isOpen, initialInput]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) {
      scrollToBottom();
    }
  }, [messages, isOpen]);

  const handleSendInternal = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: text
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
        const historyForService = messages.map(m => ({ role: m.role, text: m.text }));
        const responseText = await sendMessageToGemini(historyForService, userMsg.text);

        const aiMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            text: responseText
        };
        setMessages(prev => [...prev, aiMsg]);
    } catch (err) {
        console.error(err);
    } finally {
        setIsLoading(false);
    }
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    handleSendInternal(input);
    setInput('');
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-950/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white border border-gray-200 w-full max-w-lg rounded-[32px] shadow-2xl flex flex-col max-h-[85vh] animate-in zoom-in-95 duration-300 overflow-hidden ring-1 ring-black/5">

        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100 bg-white">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 rounded-2xl bg-gradient-to-br from-indigo-600 to-purple-700 flex items-center justify-center shadow-lg shadow-indigo-200">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
            </div>
            <div>
              <h3 className="font-black text-gray-950 text-lg">Portfolio AI</h3>
              <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">Representing Alex Aidun</p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="text-gray-400 hover:text-gray-950 hover:bg-gray-100 transition-all p-2 rounded-xl"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-gray-50/50">
          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`max-w-[85%] rounded-[24px] px-5 py-4 text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-700 text-white rounded-br-none font-bold' 
                  : 'bg-white text-gray-900 border border-gray-200 rounded-bl-none shadow-indigo-100/50 font-medium'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && (
             <div className="flex justify-start">
               <div className="bg-white border border-gray-200 text-gray-400 rounded-[20px] rounded-bl-none px-5 py-4 flex gap-1.5 items-center shadow-sm">
                 <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                 <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                 <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
               </div>
             </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Example Questions Hints */}
        {messages.length < 3 && !isLoading && (
          <div className="px-6 py-4 border-t border-gray-100 bg-white">
             <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Quick Prompts</p>
             <div className="flex flex-wrap gap-2.5">
                <button onClick={() => handleSendInternal("What's your typical tech stack?")} className="px-4 py-2.5 bg-gray-50 border-2 border-gray-100 rounded-xl text-xs font-black text-gray-800 hover:border-indigo-400 hover:text-indigo-800 transition-all shadow-sm">"What's your tech stack?"</button>
                <button onClick={() => handleSendInternal("Tell me about the Grdn outcome.")} className="px-4 py-2.5 bg-gray-50 border-2 border-gray-100 rounded-xl text-xs font-black text-gray-800 hover:border-indigo-400 hover:text-indigo-800 transition-all shadow-sm">"Tell me about Grdn."</button>
             </div>
          </div>
        )}

        {/* Input */}
        <form onSubmit={handleSend} className="p-6 bg-white border-t border-gray-100">
          <div className="relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask a question..."
              className="w-full bg-gray-50 text-gray-900 placeholder-gray-500 rounded-2xl py-5 pl-6 pr-16 focus:outline-none focus:ring-4 focus:ring-indigo-500/10 border-2 border-gray-200 focus:border-indigo-600 transition-all font-bold"
            />
            <button 
              type="submit"
              disabled={!input.trim() || isLoading}
              className="absolute right-3 top-1/2 -translate-y-1/2 p-3 bg-indigo-700 text-white rounded-xl disabled:bg-gray-200 transition-all shadow-lg shadow-indigo-200"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </div>
        </form>

      </div>
    </div>
  );
};

