                placeholder="Search outcomes, tags..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-white border-2 border-gray-300 rounded-[20px] px-6 py-4 text-base font-black text-black placeholder-gray-500 focus:outline-none focus:ring-8 focus:ring-indigo-500/10 focus:border-indigo-700 transition-all shadow-md"
              />
              <svg className="absolute right-5 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
          </div>

          <div className="flex p-2 bg-gray-200 rounded-[24px] w-fit border-2 border-gray-300 shadow-inner">
            {Object.values(ProjectCategory).map((cat) => (
              <button
                key={cat}
                onClick={() => setActiveTab(cat)}
                className={`px-8 py-3 rounded-[18px] text-sm font-black uppercase tracking-[0.2em] transition-all ${
                  activeTab === cat 
                  ? 'bg-black text-white shadow-2xl scale-[1.05]' 
                  : 'text-gray-700 hover:text-black hover:bg-white/60'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Featured Spotlight */}
      {!searchQuery && activeTab === ProjectCategory.ALL && (
        <section className="space-y-10">
          <div className="flex items-center gap-8">
            <h3 className="text-xs font-black uppercase tracking-[0.4em] text-indigo-800 bg-indigo-100 px-4 py-2 rounded-full border-2 border-indigo-200">Spotlights</h3>
            <div className="h-[3px] bg-indigo-200 flex-grow"></div>
          </div>
          <div className="grid grid-cols-1 gap-12">
            {featuredProjects.map(p => (
              <ProjectCard key={p.id} project={p} isFeatured />
            ))}
          </div>
        </section>
      )}

      {/* Main Grid */}
      <section className="space-y-10">
        {!searchQuery && activeTab === ProjectCategory.ALL && (
          <div className="flex items-center gap-8">
            <h3 className="text-xs font-black uppercase tracking-[0.4em] text-gray-600">The Catalog</h3>
            <div className="h-[3px] bg-gray-300 flex-grow"></div>
          </div>
        )}
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">
          {standardProjects.map(p => (
            <ProjectCard key={p.id} project={p} />
          ))}
        </div>

        {standardProjects.length === 0 && (
          <div className="text-center py-32 bg-white border-4 border-dashed border-gray-300 rounded-[48px] shadow-sm">
            <div className="max-w-md mx-auto px-6">
              <p className="text-black font-black text-3xl mb-4">No projects found.</p>
              <p className="text-gray-700 font-bold text-lg mb-10">Try a different search term or check another category.</p>
              <button 
                onClick={() => {setSearchQuery(''); setActiveTab(ProjectCategory.ALL);}}
                className="px-10 py-5 bg-indigo-700 text-white text-lg font-black rounded-2xl hover:bg-indigo-800 transition-all shadow-2xl shadow-indigo-200"
              >
                Clear all filters
              </button>
            </div>
          </div>
        )}
      </section>
    </div>
  );
};

export default Portfolio;

import React, { useState, useEffect, useRef } from 'react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';
import Button from './Button';

interface ChatModalProps {
  isOpen: boolean;
  onClose: () => void;
  initialInput?: string;
}

const ChatModal: React.FC<ChatModalProps> = ({ isOpen, onClose, initialInput = '' }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'model', text: "Hi! I'm Alex's AI Assistant. Ask me anything about his projects, experience, or what he's building next." }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && initialInput) {
      handleSendInternal(initialInput);
    }
  }, [isOpen, initialInput]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen) {
      scrollToBottom();
    }
  }, [messages, isOpen]);

  const handleSendInternal = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: text
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
        const historyForService = messages.map(m => ({ role: m.role, text: m.text }));
        const responseText = await sendMessageToGemini(historyForService, userMsg.text);

        const aiMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            text: responseText
        };
        setMessages(prev => [...prev, aiMsg]);
    } catch (err) {
        console.error(err);
    } finally {
        setIsLoading(false);
    }
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    handleSendInternal(input);
    setInput('');
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/70 backdrop-blur-xl animate-in fade-in duration-300">
      <div className="bg-white border-2 border-gray-300 w-full max-w-2xl rounded-[40px] shadow-2xl flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-300 overflow-hidden ring-4 ring-black/10">

        {/* Header */}
        <div className="flex items-center justify-between p-8 border-b-2 border-gray-100 bg-white">
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 rounded-[20px] bg-gradient-to-br from-indigo-700 to-purple-800 flex items-center justify-center shadow-xl shadow-indigo-300">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
            </div>
            <div>
              <h3 className="font-black text-black text-2xl">Portfolio AI</h3>
              <p className="text-xs text-gray-600 font-black uppercase tracking-[0.2em]">Representing Alex Aidun</p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="text-gray-400 hover:text-black hover:bg-gray-100 transition-all p-3 rounded-2xl"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-gray-50/70">
          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`max-w-[85%] rounded-[32px] px-7 py-5 text-base leading-relaxed shadow-md ${
                msg.role === 'user' 
                  ? 'bg-indigo-700 text-white rounded-br-none font-black' 
                  : 'bg-white text-black border-2 border-gray-200 rounded-bl-none shadow-indigo-100/50 font-bold'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && (
             <div className="flex justify-start">
               <div className="bg-white border-2 border-gray-200 text-gray-500 rounded-[24px] rounded-bl-none px-7 py-5 flex gap-2 items-center shadow-md">
                 <span className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                 <span className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                 <span className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
               </div>
             </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Example Questions Hints */}
        {messages.length < 3 && !isLoading && (
          <div className="px-8 py-6 border-t-2 border-gray-100 bg-white">
             <p className="text-xs font-black text-gray-600 uppercase tracking-[0.2em] mb-4">Quick Prompts</p>
             <div className="flex flex-wrap gap-3">
                <button onClick={() => handleSendInternal("What's your typical tech stack?")} className="px-6 py-3 bg-gray-100 border-2 border-gray-200 rounded-2xl text-sm font-black text-black hover:border-indigo-500 hover:text-indigo-800 transition-all shadow-sm">"What's your tech stack?"</button>
                <button onClick={() => handleSendInternal("Tell me about the Grdn outcome.")} className="px-6 py-3 bg-gray-100 border-2 border-gray-200 rounded-2xl text-sm font-black text-black hover:border-indigo-500 hover:text-indigo-800 transition-all shadow-sm">"Tell me about Grdn."</button>
             </div>
          </div>
        )}

        {/* Input */}
        <form onSubmit={handleSend} className="p-8 bg-white border-t-2 border-gray-100">
          <div className="relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask a question..."
              className="w-full bg-gray-50 text-black placeholder-gray-500 rounded-3xl py-6 pl-8 pr-20 focus:outline-none focus:ring-8 focus:ring-indigo-500/10 border-2 border-gray-300 focus:border-indigo-700 transition-all font-black text-lg"
            />
            <button 
              type="submit"
              disabled={!input.trim() || isLoading}
              className="absolute right-4 top-1/2 -translate-y-1/2 p-4 bg-indigo-700 text-white rounded-2xl disabled:bg-gray-200 transition-all shadow-xl shadow-indigo-300"
            >
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </div>
        </form>

      </div>
    </div>
  );
};

export default ChatModal;

